import re

def norm_doc(d):
    return re.sub(r"[^a-z0-9]", "", d.casefold())

def blocking_key(rec):
    parts = rec["name"].split()
    ap = parts[1].casefold() if len(parts) >= 2 else parts[0].casefold()
    return f"{ap}|{rec['region'].casefold()}"

def er_score(a, b):
    same_doc = norm_doc(a["doc"]) == norm_doc(b["doc"]) and bool(norm_doc(a["doc"]))
    same_block = blocking_key(a) == blocking_key(b)
    if same_doc and same_block:
        return 1.0
    if same_doc or same_block:
        return 0.5
    return 0.0

a = {"name": "Ana Quispe", "region": "Lima", "doc": "D-1"}
b = {"name": "Ana Q", "region": "Lima", "doc": "D1"}
c = {"name": "Luis Huaman", "region": "Cusco", "doc": "X"}
print(er_score(a, b), er_score(a, c))

def shared_email(a, b):
    if not a or not b:
        return False
    return a.casefold() == b.casefold()

