txs = [("A", "D", 1), ("C", "D", 1), ("A", "E", 1), ("C", "F", 1)]

def neighbors(txs, node):
    out = set()
    for x, y, _ in txs:
        if x == node:
            out.add(y)
        elif y == node:
            out.add(x)
    return out

def common_counterparties(txs, a, c):
    return sorted((neighbors(txs, a) & neighbors(txs, c)) - {a, c})

print(common_counterparties(txs, "A", "C"))

def uncertainty_band(missing, conflict):
    if conflict or len(missing) >= 2:
        return "high"
    if missing:
        return "med"
    return "low"

print(uncertainty_band([], False), "|", uncertainty_band(["x"], False), "|",
      uncertainty_band(["x", "y"], False), "|", uncertainty_band([], True))

from math import isfinite

th = {"accept_min": 0.8, "review_low": 0.4}

def decide_ops_status(score, unc, th):
    if isinstance(score, bool) or not isinstance(score, (int, float)) or not isfinite(score) or not (0 <= score <= 1):
        return "invalid_input"
    if unc not in {"low", "med", "high"}:
        return "invalid_input"
    if unc == "high":
        return "needs_review"
    if score < th["review_low"]:
        return "abstain"
    if score < th["accept_min"]:
        return "needs_review"
    return "accept_pair"

for s, u in [(0.9, "low"), (0.5, "low"), (0.2, "low"), (0.9, "high"), (True, "low")]:
    print(s, u, decide_ops_status(s, u, th))

